var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"어제 아침, 예정에 없던 일식 현상과 함께 짧은 시간 천둥번개를 동반한 국지성호우가 쏟아졌습니다.","JPN":"昨朝、突発的な日食現象とともに、\\n短時間で雷を伴った集中豪雨が発生しました。","ENG":"Yesterday morning, multiple weather anomalies occurred, including an unexpected eclipse and torrential rainfall with thunder and lightning.","TWN":"昨天早上，突然出現日蝕現象，並且短時間內降下局部性豪雨。"},"stage":{"bg":"STREET_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"환경당국은 이번 이상현상이 자연적으로는 발생할 수 없는 이례적인 재난이라며, 도시관리국의 침식재난부서에 원인 조사를 맡기기로……","JPN":"環境局は今回の異常現象について、\\n自然発生はあり得ない異例の災害と認定し、\\n都市管理局の侵食災害部署に原因調査を任せることに……","ENG":"City Management has declared a state of disaster, reporting that this doesn’t appear to be a natural occurrence, and they requested an investigation by the Corruption Disaster Department...","TWN":"環境當局稱此次異常現象，並非自然發生的罕見災難，決定委託城市管理局的侵蝕災難部門，進行相關調查……"},"stage":{"bg":"STREET_SPRING","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에, 괜찮으신가요?","JPN":"早苗様、大丈夫ですか？","ENG":"Sanae, are you alright?","TWN":"早苗，你還好嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"예, 어머니의 장례를 치러드리고 나니 한결 홀가분하군요.","JPN":"はい。母の葬儀が終わり、気持ちを整理できました。","ENG":"Yes, I feel much better after giving my mother a proper funeral.","TWN":"我沒事，辦完家母的葬禮後，覺得整個人輕鬆許多。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대의 가문이 이런 불미스러운 일을 겪게 된 것은 유감입니다.","JPN":"貴方の家門がこのような不祥事に見舞われたことを、とても心苦しく思います。","ENG":"I am sorry that your family had to go through such tragedy.","TWN":"我很抱歉，你的家族曾經歷過這樣不光彩的事情。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"공석이 아닌 개인적인 자리에서 다시 한번 사과를 드리고 싶었어요.","JPN":"公の立場ではなく個人の立場から、もう一度お詫びさせてください。","ENG":"I wanted to apologize once again personally.","TWN":"我在非公開的私人場合上再次向你道歉。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머니는…… 당주님의 도움 덕에 당신의 본분을 다할 수 있었습니다.","JPN":"母は……ご当主様のご助力のおかげで念願を果たすことができました。","ENG":"My mother... She fulfilled her duty thanks to you.","TWN":"家母……因為有堂主的幫助才能盡到本份。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"오히려 당주님께는 제가 감사를 드려야 할 일이지요.","JPN":"むしろご当主様には私が感謝しなければなりません。","ENG":"I am the one who should be thanking you.","TWN":"反而是我要感謝堂主才對。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"고마워요. 그렇게 말해줘서.","JPN":"そうおっしゃってくださって、ありがとうございます。","ENG":"Thank you for your kind words.","TWN":"謝謝你這麼說。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이제, 앞으로 어떻게 할 계획이신가요?","JPN":"それで、これからはどうする予定ですか？","ENG":"So, what’s your plan?","TWN":"之後有什麼打算呢？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"계획이라고 하심은?","JPN":"予定ということは？","ENG":"My plan?","TWN":"什麼打算？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하야미 가문이 맡아왔던 본연의 역할은 호위 무사입니다.","JPN":"速水家が果たしてきた本来の役割は護衛です。","ENG":"The Hayami family is traditionally a bodyguard family.","TWN":"速水家族原本就是護衛武士。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다시 그때처럼 돌아갈 수도 있을 거예요.","JPN":"また本来の役割に戻ることもできるでしょう。","ENG":"You may come back.","TWN":"或許能再會回復原樣，"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"물론. 그대가 원한다면 말이죠.","JPN":"もちろん、あなたが望むならです。","ENG":"If you wish.","TWN":"當然，前提是你願意。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님을 곁에서 모실 수 있다면 저에겐 거절할 이유가 없습니다.","JPN":"ご当主様をそばでお守りすることができるのでしたら、\\n私には断る理由がございません。","ENG":"I will gladly serve you, if I can.","TWN":"如果能陪在堂主身邊，我沒有理由拒絕。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"다만, 당주님의 곁을 지켜주는 분은 따로 있으니까요.","JPN":"ですが、ご当主様をそばで守ってくださる方は既にいらっしゃいますから。","ENG":"But you already have a bodyguard.","TWN":"但是，堂主身邊現在另有其人。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"호위 무사의 이름이 둘일 필요는 없습니다.","JPN":"護衛の名が二つもある必要はありません。","ENG":"You don’t need two.","TWN":"護衛武士不需要有兩位。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};